func jsonSchemaObjectTypeToPython(schema JSONObject, classDefinitions *[]string, context JSONObject, extraBehavior string, depth int, nameHint string, classNameOverride string) string {
	properties, _ := schema["properties"].(JSONObject)
	if len(properties) == 0 {
		return "dict[str, Any]"
	}
	className := jsonSchemaObjectClassName(schema, context, depth, nameHint, classNameOverride)
	required := jsonSchemaStringSetFromSlice(jsonSchemaStringSlice(schema["required"]))
	keys := make([]string, 0, len(properties))
	for key := range properties {
		keys = append(keys, key)
	}
	sort.Strings(keys)
	linesOut, usesAliases := jsonSchemaObjectFieldLines(schema, keys, properties, required, classDefinitions, context, extraBehavior, depth, className)
	if configLine := buildModelConfigLine(schema, usesAliases, extraBehavior); configLine != nil {
		linesOut = append([]string{linesOut[0], fmt.Sprint(configLine)}, linesOut[1:]...)
	}
	*classDefinitions = append(*classDefinitions, strings.Join(linesOut, "\n"))
	return className
}

func jsonSchemaObjectClassName(schema JSONObject, context JSONObject, depth int, nameHint string, classNameOverride string) string {
	if classNameOverride != "" {
		return classNameOverride
	}
	base := nameHint
	if title, ok := schema["title"].(string); ok && title != "" {
		base = title
	}
	if base == "" {
		base = "NestedModel" + strconv.Itoa(depth)
	}
	return jsonSchemaReserveClassName(base, jsonSchemaUsedClassNames(context))
}

func jsonSchemaObjectFieldLines(schema JSONObject, keys []string, properties JSONObject, required map[string]struct{}, classDefinitions *[]string, context JSONObject, extraBehavior string, depth int, className string) ([]string, bool) {
	linesOut := []string{"class " + className + "(BaseModel):"}
	usesAliases := false
	for _, propName := range keys {
		propSchema, _ := properties[propName].(JSONObject)
		if propSchema == nil {
			propSchema = jsonSchemaJSONObject(0)
		}
		propType := jsonSchemaTypeToPython(propSchema, classDefinitions, context, extraBehavior, depth+1, propName, "")
		_, isRequired := required[propName]
		if !isRequired {
			propType = "Optional[" + propType + "]"
		}
		fieldLine, fieldUsesAlias := buildFieldLine(propName, propSchema, propType, isRequired)
		linesOut = append(linesOut, fieldLine)
		usesAliases = usesAliases || fieldUsesAlias
	}
	if len(linesOut) == 1 {
		linesOut = append(linesOut, "    pass")
	}
	return linesOut, usesAliases
}

func jsonSchemaUsedClassNames(context JSONObject) map[string]struct{} {
	if context == nil {
		return map[string]struct{}{}
	}
	switch typed := context["used_class_names"].(type) {
	case map[string]struct{}:
		return typed
	case JSONObject:
		out := map[string]struct{}{}
		for key := range typed {
			out[key] = struct{}{}
		}
		context["used_class_names"] = out
		return out
	default:
		out := map[string]struct{}{}
		context["used_class_names"] = out
		return out
	}
}

func jsonSchemaGenerateModelCode(schema JSONObject, className string, extraBehavior string) string {
	if len(schema) == 0 {
		return "class " + className + "(BaseModel):\n    model_config = ConfigDict(extra='allow')\n"
	}
	classDefinitions := []string{}
	context := jsonSchemaJSONObject(3)
	context["used_class_names"] = map[string]struct{}{}
	context["ref_class_names"] = map[string]string{}
	context["defs"] = jsonSchemaJSONObject(0)
	defs := jsonSchemaJSONObject(0)
	if definitions, ok := schema["definitions"].(JSONObject); ok {
		for key, value := range definitions {
			defs[key] = value
		}
	}
	if dollarDefs, ok := schema["$defs"].(JSONObject); ok {
		for key, value := range dollarDefs {
			defs[key] = value
		}
	}
	context["defs"] = defs
	refClassNames, ok := context["ref_class_names"].(map[string]string)
	if !ok {
		refClassNames = map[string]string{}
		context["ref_class_names"] = refClassNames
	}
	for defName := range defs {
		refClassNames[defName] = jsonSchemaReserveClassName(defName, jsonSchemaUsedClassNames(context))
	}
	for _, defName := range jsonSchemaTopoSortDefs(defs) {
		if defSchema, ok := defs[defName].(JSONObject); ok && defSchema["type"] == "object" && defSchema["properties"] != nil {
			jsonSchemaTypeToPython(defSchema, &classDefinitions, context, extraBehavior, 0, defName, refClassNames[defName])
		}
	}
	rootSchema := schema
	if rootSchema["type"] != "object" {
		if resolved, ok := resolveLocalRefSchema(rootSchema, context).(JSONObject); ok && resolved["type"] == "object" {
			rootSchema = resolved
		} else {
			return "class " + className + "(BaseModel):\n    model_config = ConfigDict(extra='allow')\n"
		}
	}
	properties, _ := rootSchema["properties"].(JSONObject)
	required := jsonSchemaStringSetFromSlice(jsonSchemaStringSlice(rootSchema["required"]))
	keys := make([]string, 0, len(properties))
	for key := range properties {
		keys = append(keys, key)
	}
	sort.Strings(keys)
	linesOut := []string{"class " + className + "(BaseModel):"}
	fieldLines := []string{}
	usesAliases := false
	for _, propName := range keys {
		propSchema, _ := properties[propName].(JSONObject)
		if propSchema == nil {
			propSchema = jsonSchemaJSONObject(0)
		}
		propType := jsonSchemaTypeToPython(propSchema, &classDefinitions, context, extraBehavior, 0, propName, "")
		_, isRequired := required[propName]
		if !isRequired {
			propType = "Optional[" + propType + "]"
		}
		fieldLine, fieldUsesAlias := buildFieldLine(propName, propSchema, propType, isRequired)
		fieldLines = append(fieldLines, fieldLine)
		usesAliases = usesAliases || fieldUsesAlias
	}
	if configLine := buildModelConfigLine(rootSchema, usesAliases, extraBehavior); configLine != nil {
		linesOut = append(linesOut, fmt.Sprint(configLine))
	}
	linesOut = append(linesOut, fieldLines...)
	if len(linesOut) == 1 {
		linesOut = append(linesOut, "    pass")
	}
	allCode := strings.Join(classDefinitions, "\n\n")
	if allCode != "" {
		allCode += "\n\n"
	}
	allCode += strings.Join(linesOut, "\n")
	rebuildNames := []string{}
	for _, definition := range classDefinitions {
		for _, line := range strings.Split(definition, "\n") {
			if strings.HasPrefix(line, "class ") && strings.Contains(line, "(BaseModel):") {
				name := strings.TrimPrefix(line, "class ")
				name = strings.Split(name, "(BaseModel):")[0]
				rebuildNames = append(rebuildNames, name)
			}
		}
	}
	rebuildNames = append(rebuildNames, className)
	if len(rebuildNames) > 0 {
		rebuildLines := make([]string, 0, len(rebuildNames))
		for _, name := range rebuildNames {
			rebuildLines = append(rebuildLines, sanitizeClassName(name)+".model_rebuild()")
		}
		allCode += "\n" + strings.Join(rebuildLines, "\n")
	}
	return allCode
}

func __retabCoreJsonSchemaToPydanticStringSliceContains(values []string, value string) bool {
	for _, item := range values {
		if item == value {
			return true
		}
	}
	return false
}

// JSON type aliases the emitter needs, copied from base.go in the same core-go package.
type JSONValue = any
type JSONObject = map[string]JSONValue
type JSONArray = []JSONValue
